def find_policy(self, flow, state, context, tools):
    slots = flow.slot_values_dict()
    query = slots.get('query', '')
    limit = int(slots['count']) if 'count' in slots else 10

    terms = self._expand_query(query)

    seen = {}
    any_ok = False
    for term in terms:
        result = tools('find_posts', {'query': term, 'count': limit})
        if result.get('_success'):
            any_ok = True
            for post in result.get('posts', []):
                seen.setdefault(post['post_id'], post)

    results = list(seen.values())[:limit]

    if not any_ok:
        return self.error_frame(flow, 'tool_error',
            thoughts='find_posts failed on every expanded query term.',
            failed_tool='find_posts')

    flow.status = 'Completed'
    frame = DisplayFrame(flow.name(),
        thoughts=f"Found {len(results)} posts matching '{query}'.",
        metadata={
            'query': query,
            'hit_count': len(results),
            'expanded_terms': terms,
        })
    frame.add_block({'type': 'list', 'data': {
        'items': [{
            'post_id': p['post_id'],
            'title': p['title'],
            'excerpt': p.get('preview', ''),
            'publish_date': p.get('updated_at'),
            'score': p.get('score'),
        } for p in results],
    }})
    return frame

class FindFlow(ResearchParentFlow):
  def __init__(self):
    super().__init__()
    self.flow_type = 'find'
    self.dax = '{001}'
    self.entity_slot = 'query'
    self.goal = 'search previous posts by keyword or topic; returns matching titles, excerpts, and publication dates sorted by relevance'
    self.slots = {
      'query': ExactSlot(),
      'count': LevelSlot(priority='optional', threshold=1),
    }
    self.tools = ['find_posts']
